   341→    private Optional<Compression> getCompression() {
   342→        switch (compressionType) {
   343→            case GZIP:
   344→                return Optional.of(Compression.gzip()
   345→                        .level(getInt(TopicConfig.COMPRESSION_GZIP_LEVEL_CONFIG))
   346→                        .build());
   347→            case LZ4:
   348→                return Optional.of(Compression.lz4()
   349→                        .level(getInt(TopicConfig.COMPRESSION_LZ4_LEVEL_CONFIG))
   350→                        .build());
   351→            case ZSTD:
   352→                return Optional.of(Compression.zstd()
   353→                        .level(getInt(TopicConfig.COMPRESSION_ZSTD_LEVEL_CONFIG))
   354→                        .build());
   355→            case SNAPPY:
   356→                return Optional.of(Compression.snappy().build());
   357→            case UNCOMPRESSED:
   358→                return Optional.of(Compression.NONE);
   359→            case PRODUCER:
   360→                return Optional.empty();
   361→            default:
   362→                throw new IllegalArgumentException("Invalid value for " + TopicConfig.COMPRESSION_TYPE_CONFIG);
   363→        }
   364→    }
