   557→    public static void validateRemoteStorageOnlyIfSystemEnabled(Map<?, ?> props, boolean isRemoteLogStorageSystemEnabled, boolean isReceivingConfigFromStore) {
   558→        boolean isRemoteLogStorageEnabled = (Boolean) props.get(TopicConfig.REMOTE_LOG_STORAGE_ENABLE_CONFIG);
   559→        if (isRemoteLogStorageEnabled && !isRemoteLogStorageSystemEnabled) {
   560→            if (isReceivingConfigFromStore) {
   561→                throw new ConfigException("You have to delete all topics with the property remote.storage.enable=true before disabling tiered storage cluster-wide");
   562→            } else {
   563→                throw new ConfigException("Tiered Storage functionality is disabled in the broker. " +
   564→                        "Topic cannot be configured with remote log storage.");
   565→            }
   566→        }
   567→    }
